SELECT t1.id as entrustmentId, t1.entrustment_no AS entrustmentNo, IFNULL( CONCAT( t1.entrust_category_type, t1.entrustment_no ), t1.entrustment_no ) AS entrustmentNostr, t1.entrust_company AS entrustCompany, GROUP_CONCAT( t3.alias_name SEPARATOR ', ' ) AS sampleName FROM test_entrusted_info AS t1 LEFT JOIN test_entrusted_sample_details_rel AS t2 ON t1.id = t2.entrustment_id LEFT JOIN test_sample AS t3 ON t2.sample_id = t3.id WHERE t1.entrustment_no IN
#{item.entrustmentNo}
AND t1.entrust_category_type IS NULL GROUP BY t1.id
